import{c as i,Z as t,Q as o,j as l,o as r,m as n}from"./chunks/framework.qjzPVSkb.js";const b=JSON.parse('{"title":"Gemini","description":"Google 出品的多模态 AI 模型——1M 上下文窗口，与 Google 生态深度集成","frontmatter":{"title":"Gemini","description":"Google 出品的多模态 AI 模型——1M 上下文窗口，与 Google 生态深度集成","difficulty":"beginner"},"headers":[],"relativePath":"tools/gemini.md","filePath":"tools/gemini.md"}'),d={name:"tools/gemini.md"};function h(s,e,m,c,g,u){const a=t("DifficultyBadge");return o(),l("div",null,[r(a,{level:"beginner"}),e[0]||(e[0]=n('<h1 id="gemini" tabindex="-1">Gemini <a class="header-anchor" href="#gemini" aria-label="Permalink to &quot;Gemini&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>Google 多模态模型</strong>——1M 超长上下文 + Google 全家桶集成，适合超长文档处理与 Google 生态用户。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>Google</td></tr><tr><td>价格</td><td>免费 / Gemini Advanced $19.99/月</td></tr><tr><td>主要模型</td><td>Gemini 2.0 Flash / Gemini 2.0 Pro</td></tr><tr><td>上下文窗口</td><td>1M tokens（Pro）/ 1M tokens（Flash）</td></tr><tr><td>首发时间</td><td>2023 年 12 月</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🌐-1m-超长上下文" tabindex="-1">🌐 1M 超长上下文 <a class="header-anchor" href="#🌐-1m-超长上下文" aria-label="Permalink to &quot;🌐 1M 超长上下文&quot;">​</a></h3><p>Gemini 的 1M tokens 上下文是目前公开服务中最长的之一。你可以一次性处理：</p><ul><li>1 小时的视频内容</li><li>11 小时的音频内容</li><li>超过 30,000 行代码</li><li>超过 700,000 个单词</li></ul><h3 id="🔗-google-生态集成" tabindex="-1">🔗 Google 生态集成 <a class="header-anchor" href="#🔗-google-生态集成" aria-label="Permalink to &quot;🔗 Google 生态集成&quot;">​</a></h3><p>与 Gmail、Google Docs、Google Drive、YouTube 等深度集成。可以在 Gmail 中直接让 Gemini 帮你整理邮件，或在 Google Docs 中辅助写作。</p><h3 id="🎯-多模态能力" tabindex="-1">🎯 多模态能力 <a class="header-anchor" href="#🎯-多模态能力" aria-label="Permalink to &quot;🎯 多模态能力&quot;">​</a></h3><p>Gemini 从一开始就是多模态原生模型——它同时理解文本、图像、音频、视频和代码。你可以上传一段视频让它分析内容。</p><h3 id="🤖-gemini-advanced" tabindex="-1">🤖 Gemini Advanced <a class="header-anchor" href="#🤖-gemini-advanced" aria-label="Permalink to &quot;🤖 Gemini Advanced&quot;">​</a></h3><p>付费版提供更强的模型（2.0 Pro）、更大的上下文、优先访问新功能，并包含 2TB Google One 存储。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>超长上下文（1M）</strong>：处理超大规模内容的能力独一无二</li><li><strong>Google 生态</strong>：如果你是 Google 全家桶用户，Gemini 的集成体验最流畅</li><li><strong>免费额度</strong>：免费版功能已相当强大，Flash 模型响应快</li><li><strong>多模态原生</strong>：视频、音频理解是其他产品难以匹敌的</li><li><strong>AI Studio</strong>：开发者可以通过 Google AI Studio 免费试用 API</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li>中文能力不如国产模型</li><li>Google 服务在国内访问不便</li><li>免费版的高级功能有限</li><li>图像生成能力不如 Midjourney/DALL·E</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ Google 生态重度用户</li><li>✅ 需要处理视频、音频等多模态内容的用户</li><li>✅ 需要超长文档（超过 200K tokens）处理的场景</li><li>✅ 对 Google AI Studio / API 感兴趣的开发者</li><li>⚠️ 国内用户可能需要科学上网，中文场景建议优先国产模型</li></ul><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/multimodal.html">多模态</a> —— 理解 Gemini 的原生多模态能力</li><li><a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> —— 1M tokens 意味着什么</li><li><a href="/ai-knowledge/practices/rag-knowledge-base.html">搭建 RAG 知识库</a> —— 突破上下文限制的另一种思路</li></ul>',23))])}const f=i(d,[["render",h]]);export{b as __pageData,f as default};
